import {
  Children,
  forwardRef,
  type HTMLAttributes,
  isValidElement,
  type KeyboardEvent,
  type MouseEvent,
  type ReactNode,
  useEffect,
  useId,
  useMemo,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { Popper } from '../Overlay';
import { type SubMenuContextValue, SubMenuContext, useMenuContext, useSubMenuContext } from './Menu';
import { MenuItem } from './MenuItem';

export interface SubMenuProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  /** Unique identifier for the sub-menu. */
  index: string;
  /** Title rendered in the sub-menu trigger. */
  title?: ReactNode;
  /** Leading icon. */
  icon?: ReactNode;
  /** Disable interaction. */
  disabled?: boolean;
  children?: ReactNode;
}

function ChevronIcon() {
  return (
    <svg
      className="ec-sub-menu__arrow"
      viewBox="0 0 1024 1024"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <path
        fill="currentColor"
        d="M831.872 340.864 512 652.672 192.128 340.864a30.592 30.592 0 0 0-42.752 0 29.12 29.12 0 0 0 0 41.6L489.664 714.24a32 32 0 0 0 44.672 0l340.288-331.776a29.12 29.12 0 0 0 0-41.6 30.592 30.592 0 0 0-42.752 0z"
      />
    </svg>
  );
}

/** Collect the `index` of every MenuItem descendant so the sub-menu can reflect active state. */
function collectItemIndices(children: ReactNode, indices: string[]): void {
  Children.forEach(children, (child) => {
    if (!isValidElement(child)) {
      return;
    }
    if (child.type === MenuItem) {
      const idx = (child.props as { index?: string }).index;
      if (idx) {
        indices.push(idx);
      }
      return;
    }
    const grandChildren = (child.props as { children?: ReactNode }).children;
    if (grandChildren) {
      collectItemIndices(grandChildren, indices);
    }
  });
}

export const SubMenu = forwardRef<HTMLDivElement, SubMenuProps>(function SubMenu(props, ref) {
  const { index, title, icon, disabled = false, className, style, children, ...rest } = props;

  const ns = useNamespace('sub-menu');
  const menu = useMenuContext();
  const parent = useSubMenuContext();
  const popupId = useId();

  const mode = menu?.mode ?? 'vertical';
  // `openedMenus` drives both vertical (inline) and horizontal (popup) open state,
  // so the popup is controlled and its expanded state is observable to context.
  const open = menu?.openedMenus.includes(index) ?? false;

  const childIndices: string[] = [];
  collectItemIndices(children, childIndices);
  const isActive = menu?.activeIndex ? childIndices.includes(menu.activeIndex) : false;

  // Register this sub-menu's parent path so `uniqueOpened` can preserve ancestors.
  const parentIndex = parent?.parentIndex ?? null;
  const registerSubMenu = menu?.registerSubMenu;
  const unregisterSubMenu = menu?.unregisterSubMenu;
  useEffect(() => {
    registerSubMenu?.(index, parentIndex);
    return () => unregisterSubMenu?.(index);
  }, [registerSubMenu, unregisterSubMenu, index, parentIndex]);

  // Expose this sub-menu as the parent path for its descendants.
  const subMenuContext = useMemo<SubMenuContextValue>(() => ({ parentIndex: index }), [index]);

  const handleTitleClick = (event: MouseEvent<HTMLDivElement>) => {
    if (disabled) {
      return;
    }
    // The trigger role lives on the `<div>`; stop the event from bubbling to an
    // enclosing (ancestor) sub-menu trigger `<div>`.
    event.stopPropagation();
    menu?.toggleMenu(index);
  };

  const handleTitleKeyDown = (event: KeyboardEvent<HTMLDivElement>) => {
    if (disabled) {
      return;
    }
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      event.stopPropagation();
      menu?.toggleMenu(index);
    } else if (event.key === 'ArrowDown') {
      event.preventDefault();
      event.stopPropagation();
      menu?.openMenu(index);
    } else if (event.key === 'Escape' && open) {
      event.preventDefault();
      event.stopPropagation();
      menu?.closeMenu(index);
    }
  };

  // The title span is the menuitem's direct text content, so it remains the
  // accessible name of the trigger. The icon and arrow sit inside it; a nested
  // `role="menu"` (the popup) is a sibling, not part of the name.
  const titleContent = (
    <span className={ns.e('title')}>
      {icon && <span className={ns.e('icon')}>{icon}</span>}
      <span className={ns.e('label')}>{title}</span>
      <span className={cls(ns.e('arrow-wrap'), ns.is('opened', open))}>
        <ChevronIcon />
      </span>
    </span>
  );

  // The trigger `<div>` carries `role="menuitem"`, so it is a valid direct child
  // of its `menu`/`menubar`/`group` parent without emitting any `li`.
  const triggerClasses = cls(
    ns.b(),
    ns.is('opened', open),
    ns.is('active', isActive),
    ns.is('disabled', disabled),
  );

  // Horizontal mode renders the children in a Popper popup. The Popper is
  // controlled by the menu context so the trigger can open it via keyboard and
  // its expanded state stays in sync with `openedMenus`. The floating box
  // carries `role="menu"`, so its `<div role="menuitem">` children get a valid
  // required parent without an intervening role.
  if (mode === 'horizontal') {
    // `aria-controls`/`aria-expanded` are supplied by the Popper's floating
    // interactions (pointing at the real floating element), so they are not
    // set explicitly here to avoid a dangling reference.
    const reference = (
      <div
        ref={ref}
        role="menuitem"
        className={cls(triggerClasses, className)}
        style={style}
        tabIndex={disabled ? -1 : 0}
        aria-haspopup="menu"
        aria-disabled={disabled || undefined}
        onKeyDown={handleTitleKeyDown}
        {...rest}
      >
        {titleContent}
      </div>
    );

    return (
      <SubMenuContext.Provider value={subMenuContext}>
        <Popper
          reference={reference}
          open={open}
          onOpenChange={(next) => {
            if (disabled) {
              return;
            }
            if (next) {
              menu?.openMenu(index);
            } else {
              menu?.closeMenu(index);
            }
          }}
          trigger="hover"
          placement="bottom-start"
          offset={6}
          role="menu"
          disabled={disabled}
          popperClass="ec-menu__popper"
        >
          {/* The Popper floating box is the single `role="menu"`; the items
              render directly as its `<div role="menuitem">` children, so the
              menu owns only menuitems and introduces no stray role. */}
          {children}
        </Popper>
      </SubMenuContext.Provider>
    );
  }

  // Vertical mode expands and collapses inline. The `<div>` is the trigger
  // (`role="menuitem"`) and owns an inline `<div role="menu">` that it renders
  // as a child, so the submenu's menuitems get a valid `menu` parent and that
  // `menu` is owned by the menuitem.
  return (
    <div
      ref={ref}
      role="menuitem"
      className={cls(triggerClasses, className)}
      style={style}
      tabIndex={disabled ? -1 : 0}
      aria-haspopup="menu"
      aria-expanded={open}
      // Only reference the inline menu while it is mounted (it renders on open),
      // so `aria-controls` never points at a missing element.
      aria-controls={open ? popupId : undefined}
      aria-disabled={disabled || undefined}
      onClick={handleTitleClick}
      onKeyDown={handleTitleKeyDown}
      {...rest}
    >
      {titleContent}
      {open && (
        <div id={popupId} role="menu" className={ns.e('content')}>
          <SubMenuContext.Provider value={subMenuContext}>{children}</SubMenuContext.Provider>
        </div>
      )}
    </div>
  );
});

export * from './Menu';
export * from './MenuItem';
export * from './SubMenu';
export * from './MenuItemGroup';

.ec-menu {
  --ec-menu-item-height: 56px;
  --ec-menu-horizontal-item-height: 60px;
  --ec-menu-sub-item-height: 50px;
  --ec-menu-item-font-size: var(--ec-font-size-base);
  --ec-menu-padding-horizontal: 20px;
  --ec-menu-base-level-padding: 20px;
  --ec-menu-level-padding: 20px;
  --ec-menu-icon-width: 24px;
  --ec-menu-text-color: var(--ec-text-color-regular);
  --ec-menu-hover-text-color: var(--ec-text-color-primary);
  --ec-menu-active-color: var(--ec-color-primary);
  --ec-menu-disabled-color: var(--ec-disabled-text-color);
  --ec-menu-bg-color: var(--ec-fill-color-blank);
  --ec-menu-hover-bg-color: var(--ec-fill-color-light);
  --ec-menu-border-color: var(--ec-border-color-light);

  box-sizing: border-box;
  margin: 0;
  padding: 0;
  font-family: var(--ec-font-family);
  font-size: var(--ec-menu-item-font-size);
  background-color: var(--ec-menu-bg-color);
}

.ec-menu *,
.ec-menu *::before,
.ec-menu *::after {
  box-sizing: border-box;
}

/* ---- Vertical layout ---- */
.ec-menu--vertical {
  display: flex;
  flex-direction: column;
  border-right: var(--ec-border-width) var(--ec-border-style) var(--ec-menu-border-color);
}

.ec-menu--vertical.is-collapse {
  --ec-menu-padding-horizontal: 0;
  width: var(--ec-menu-item-height);
}

.ec-menu--vertical.is-collapse .ec-menu-item__title,
.ec-menu--vertical.is-collapse .ec-sub-menu__label,
.ec-menu--vertical.is-collapse .ec-sub-menu__arrow-wrap,
.ec-menu--vertical.is-collapse .ec-menu-item-group__title {
  display: none;
}

.ec-menu--vertical.is-collapse .ec-menu-item,
.ec-menu--vertical.is-collapse .ec-sub-menu__title {
  justify-content: center;
  padding-left: 0;
  padding-right: 0;
}

.ec-menu--vertical.is-collapse .ec-sub-menu__icon {
  width: auto;
}

.ec-menu--vertical.is-collapse .ec-sub-menu__content {
  display: none;
}

/* ---- Horizontal layout ---- */
.ec-menu--horizontal {
  display: flex;
  flex-direction: row;
  align-items: center;
  border-bottom: var(--ec-border-width) var(--ec-border-style) var(--ec-menu-border-color);
}

.ec-menu--horizontal > .ec-menu-item,
.ec-menu--horizontal > .ec-sub-menu {
  height: var(--ec-menu-horizontal-item-height);
  border-bottom: 2px solid transparent;
}

.ec-menu--horizontal > .ec-menu-item.is-active,
.ec-menu--horizontal > .ec-sub-menu.is-active {
  color: var(--ec-menu-active-color);
  border-bottom-color: var(--ec-menu-active-color);
}

/* In horizontal mode the sub-menu trigger has no inline content of its own;
   its title row fills the trigger height. */
.ec-menu--horizontal > .ec-sub-menu {
  display: flex;
  align-items: stretch;
}

.ec-menu--horizontal > .ec-sub-menu > .ec-sub-menu__title {
  align-items: center;
}

/* ---- Menu item ---- */
.ec-menu-item {
  display: flex;
  align-items: center;
  gap: 6px;
  box-sizing: border-box;
  height: var(--ec-menu-item-height);
  padding: 0 var(--ec-menu-padding-horizontal);
  margin: 0;
  font-size: var(--ec-menu-item-font-size);
  line-height: var(--ec-menu-item-height);
  white-space: nowrap;
  color: var(--ec-menu-text-color);
  cursor: pointer;
  outline: none;
  user-select: none;
  transition: var(--ec-transition-all);
}

.ec-menu-item:hover {
  color: var(--ec-menu-hover-text-color);
  background-color: var(--ec-menu-hover-bg-color);
}

/* The `<div>` itself is the focusable `menuitem`; the focus ring is drawn
   directly on it. */
.ec-menu-item:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: -2px;
}

.ec-menu-item.is-active {
  color: var(--ec-menu-active-color);
}

.ec-menu-item.is-disabled {
  color: var(--ec-menu-disabled-color);
  cursor: not-allowed;
  background: none;
  opacity: 0.75;
}

.ec-menu-item.is-disabled:hover {
  background: none;
  color: var(--ec-menu-disabled-color);
}

.ec-menu-item__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--ec-menu-icon-width);
  font-size: 18px;
}

.ec-menu-item__title {
  display: inline-flex;
  align-items: center;
}

/* ---- Sub-menu ---- */
/* The `<div role="menuitem">` is the `.ec-sub-menu` trigger; it owns the inline
   (vertical) `<div role="menu">` content as a child. The `.ec-sub-menu__title`
   span is the flex row that holds the icon, label and arrow. */
.ec-sub-menu {
  box-sizing: border-box;
  color: var(--ec-menu-text-color);
  cursor: pointer;
  outline: none;
  user-select: none;
}

.ec-sub-menu__title {
  display: flex;
  align-items: center;
  gap: 6px;
  box-sizing: border-box;
  padding: 0 var(--ec-menu-padding-horizontal);
  font-size: var(--ec-menu-item-font-size);
  white-space: nowrap;
  transition: var(--ec-transition-all);
}

.ec-sub-menu:hover > .ec-sub-menu__title {
  color: var(--ec-menu-hover-text-color);
  background-color: var(--ec-menu-hover-bg-color);
}

.ec-sub-menu:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: -2px;
}

.ec-sub-menu.is-active > .ec-sub-menu__title {
  color: var(--ec-menu-active-color);
}

.ec-sub-menu.is-disabled {
  color: var(--ec-menu-disabled-color);
  cursor: not-allowed;
  opacity: 0.75;
}

.ec-sub-menu.is-disabled:hover > .ec-sub-menu__title {
  background: none;
  color: var(--ec-menu-disabled-color);
}

.ec-sub-menu__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--ec-menu-icon-width);
  height: var(--ec-menu-item-height);
  font-size: 18px;
}

.ec-sub-menu__label {
  flex: 1;
  display: inline-flex;
  align-items: center;
  height: var(--ec-menu-item-height);
  line-height: var(--ec-menu-item-height);
}

.ec-sub-menu__arrow-wrap {
  display: inline-flex;
  align-items: center;
  height: var(--ec-menu-item-height);
  margin-left: auto;
  transition: transform var(--ec-transition-duration);
}

.ec-sub-menu__arrow-wrap.is-opened {
  transform: rotate(180deg);
}

.ec-sub-menu__arrow {
  width: 14px;
  height: 14px;
}

/* ---- Inline (vertical) sub-menu content ---- */
/* Rendered only while the sub-menu is open (mounted on demand), so no
   max-height transition is needed; it is a block that stacks below the title. */
.ec-sub-menu__content {
  width: 100%;
  margin: 0;
  padding: 0;
}

/* Indentation for nested vertical items. */
.ec-menu--vertical .ec-sub-menu__content .ec-menu-item {
  height: var(--ec-menu-sub-item-height);
  line-height: var(--ec-menu-sub-item-height);
}

.ec-menu--vertical .ec-sub-menu__content .ec-menu-item,
.ec-menu--vertical .ec-sub-menu__content .ec-sub-menu__title {
  padding-left: calc(var(--ec-menu-base-level-padding) + var(--ec-menu-level-padding));
  background-color: var(--ec-fill-color-lighter);
}

/* Nested sub-menu title rows match the sub-item height. */
.ec-menu--vertical .ec-sub-menu__content > .ec-sub-menu > .ec-sub-menu__title > .ec-sub-menu__icon,
.ec-menu--vertical .ec-sub-menu__content > .ec-sub-menu > .ec-sub-menu__title > .ec-sub-menu__label,
.ec-menu--vertical
  .ec-sub-menu__content
  > .ec-sub-menu
  > .ec-sub-menu__title
  > .ec-sub-menu__arrow-wrap {
  height: var(--ec-menu-sub-item-height);
  line-height: var(--ec-menu-sub-item-height);
}

.ec-menu--vertical .ec-sub-menu__content .ec-sub-menu__content .ec-menu-item,
.ec-menu--vertical .ec-sub-menu__content .ec-sub-menu__content .ec-sub-menu__title {
  padding-left: calc(var(--ec-menu-base-level-padding) + var(--ec-menu-level-padding) * 2);
}

/* ---- Horizontal sub-menu popup (rendered through Popper) ---- */
.ec-menu__popper {
  padding: 5px 0;
  min-width: 200px;
  background-color: var(--ec-menu-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-border-color-light);
  border-radius: var(--ec-border-radius-base);
  box-shadow: var(--ec-box-shadow-light);
}

/* Items render directly inside the floating `role="menu"` box. */
.ec-menu__popper .ec-menu-item {
  height: var(--ec-menu-sub-item-height);
  line-height: var(--ec-menu-sub-item-height);
}

.ec-menu__popper .ec-sub-menu__title > .ec-sub-menu__icon,
.ec-menu__popper .ec-sub-menu__title > .ec-sub-menu__label,
.ec-menu__popper .ec-sub-menu__title > .ec-sub-menu__arrow-wrap {
  height: var(--ec-menu-sub-item-height);
  line-height: var(--ec-menu-sub-item-height);
}

/* ---- Menu item group ---- */
.ec-menu-item-group {
  box-sizing: border-box;
  padding: 0;
  margin: 0;
}

.ec-menu-item-group__title {
  padding: 8px 0 8px var(--ec-menu-padding-horizontal);
  font-size: var(--ec-font-size-small);
  line-height: 1;
  color: var(--ec-text-color-secondary);
}
